using LearnKit.Application.Roadmaps.Admin.Contracts;
namespace LearnKit.Application.Roadmaps.Admin.Commands.ReorderLearningZones;
public sealed class ReorderLearningZonesHandler(ILearningPathManagementStore store) { public async Task<bool> HandleAsync(ReorderLearningZonesCommand command,CancellationToken cancellationToken=default){ var path=await store.GetTrackedPathByIdAsync(command.LearningPathId,cancellationToken); if(path is null)return false; try { path.ReorderZones(command.OrderedZoneIds); } catch (ArgumentException) { return false; } await store.SaveChangesAsync(cancellationToken); return true; } }
